import {
  type Container,
  type ContainerID,
  type Delta,
  isContainer,
  LoroList,
  LoroMap,
  type LoroEvent,
  type LoroEventBatch,
  LoroText,
  type MapDiff,
  type TextDiff,
  type Value,
} from "loro-crdt";
import { Fragment, type Mark, type Node, type Schema } from "prosemirror-model";
import { type EditorState, type Transaction } from "prosemirror-state";

import {
  ATTRIBUTES_KEY,
  createNodeFromLoroObj,
  type LoroDocType,
  type LoroNodeContainerType,
  type LoroNodeMapping,
  NODE_NAME_KEY,
  WEAK_NODE_TO_LORO_CONTAINER_MAPPING,
} from "./lib";

/**
 * Information about where a Loro container resides in the ProseMirror tree.
 */
export interface ContainerLocation {
  /**
   * The PM Node bound to this container. For a `LoroText` this is the array
   * of inline text nodes (PM stores rich text as a sequence of text nodes,
   * each carrying its own marks).
   */
  node: Node | Node[];
  /**
   * The absolute PM position of `node`. For a non-text container it is the
   * position of the node itself (its opening token). For a `LoroText` it is
   * the position of the first character of the text run inside its parent
   * block, so that text-delta offsets compose 1:1 with PM positions.
   */
  pos: number;
  /** `true` when the container is a `LoroText` (mapped to `Node[]`). */
  isText: boolean;
}

/**
 * Find the position of a Loro container inside a ProseMirror doc.
 *
 * Returns `null` when the container has no PM mapping yet — for example when
 * a brand-new container has just arrived via a remote update and the parent
 * has not been re-walked, or when a `LoroText` has been emptied and pruned
 * from the mapping by `updateLoroToPmState`. Callers handling text events
 * should fall back to {@link findEmptyTextPosition} in that case.
 *
 * Pass an optional `cache` to memoise lookups across an event batch — the
 * walk over `doc.descendants` is O(N) per call, so without a cache a
 * batch of M events on a doc of size N is O(N·M).
 */
export function findContainerLocation(
  doc: Node,
  containerId: ContainerID,
  mapping: LoroNodeMapping,
  cache?: Map<ContainerID, ContainerLocation | null>,
  loroDoc?: LoroDocType,
): ContainerLocation | null {
  if (doc == null || containerId == null || mapping == null) {
    return null;
  }
  if (cache != null) {
    const cached = cache.get(containerId);
    if (cached !== undefined) {
      return cached;
    }
  }
  const result = findContainerLocationUncached(doc, containerId, mapping, loroDoc);
  if (cache != null) {
    cache.set(containerId, result);
  }
  return result;
}

function findContainerLocationUncached(
  doc: Node,
  containerId: ContainerID,
  mapping: LoroNodeMapping,
  loroDoc?: LoroDocType,
): ContainerLocation | null {
  const mapped = mapping.get(containerId);
  if (mapped == null) {
    return null;
  }

  if (Array.isArray(mapped)) {
    if (mapped.length === 0) {
      return null;
    }
    const firstText = mapped[0];
    let runStart: number | null = null;
    doc.descendants((node, pos) => {
      if (runStart != null) {
        return false;
      }
      let offset = 0;
      for (let i = 0; i < node.childCount; i++) {
        const child = node.child(i);
        if (child === firstText) {
          runStart = pos + 1 + offset;
          return false;
        }
        offset += child.nodeSize;
      }
      return true;
    });
    if (runStart == null) {
      return null;
    }
    return { node: mapped, pos: runStart, isText: true };
  }

  if (mapped === doc) {
    return { node: mapped, pos: 0, isText: false };
  }

  let foundPos: number | null = null;
  doc.descendants((node, pos) => {
    if (foundPos != null) {
      return false;
    }
    if (node === mapped) {
      foundPos = pos;
      return false;
    }
    return true;
  });
  if (foundPos == null) {
    // The mapped node is not in the doc by object identity, and
    // WEAK_NODE_TO_LORO_CONTAINER_MAPPING didn't find it either.
    // This can happen when another plugin creates a new node object
    // (e.g. via setNodeMarkup) after the fallback dispatch.
    // As a last resort, find the node by walking the mapping entries
    // and checking which doc node has the same ContainerID via the
    // reverse WeakMap.
    doc.descendants((node, pos) => {
      if (foundPos != null) return false;
      const cid = WEAK_NODE_TO_LORO_CONTAINER_MAPPING.get(node);
      if (cid === containerId) {
        foundPos = pos;
        // Update the mapping to point to the current node
        mapping.set(containerId, node);
        return false;
      }
      return true;
    });
  }
  if (foundPos == null) {
    // The mapped node is not in the doc by object identity, and
    // WEAK_NODE_TO_LORO_CONTAINER_MAPPING didn't find it either.
    // As a last resort, if we have the Loro doc, compute the position
    // from the Loro tree structure.
    if (loroDoc != null) {
      const container = loroDoc.getContainerById(containerId);
      if (container instanceof LoroMap) {
        const pos = computeBlockPosFromLoro(
          container as LoroMap<LoroNodeContainerType>,
          doc,
          loroDoc,
          mapping,
        );
        if (pos != null) {
          foundPos = pos;
          try {
            const actualNode = doc.nodeAt(pos);
            if (actualNode) {
              mapping.set(containerId, actualNode);
              WEAK_NODE_TO_LORO_CONTAINER_MAPPING.set(actualNode, containerId);
            }
          } catch (_) { /* ignore */ }
        }
      }
    }
  }
  if (foundPos == null) {
    return null;
  }
  return { node: mapped, pos: foundPos, isText: false };
}

/**
 * Compute the PM position of a block-level Loro container by walking the
 * Loro tree structure. This is a fallback for when the mapping has a stale
 * node reference. It sums the sizes of all preceding siblings in the Loro
 * tree to compute the absolute PM position.
 *
 * Returns null if the container cannot be found in the Loro tree.
 */
function computeBlockPosFromLoro(
  blockMap: LoroMap<LoroNodeContainerType>,
  pmDoc: import("prosemirror-model").Node,
  loroDoc: LoroDocType,
  mapping: LoroNodeMapping,
): number | null {
  // Find the parent list of this block
  const parentList = blockMap.parent();
  if (!(parentList instanceof LoroList)) {
    return null;
  }
  const grandParent = parentList.parent();
  if (!(grandParent instanceof LoroMap)) {
    return null;
  }

  // Find grandParent's position in the PM doc
  let grandParentPos = 0;
  const grandParentMapped = mapping.get(grandParent.id);
  // For the root doc, grandParentMapped might be stale. Check if it's the
  // actual pmDoc by type, or fall back to position 0 for the root.
  const isRootDoc = grandParent.id === "cid:root-doc:Map" || grandParent.id.startsWith("cid:root-doc:");
  if (isRootDoc) {
    grandParentPos = 0; // root doc is always at position 0
  } else if (grandParentMapped && !Array.isArray(grandParentMapped)) {
    let found = false;
    pmDoc.descendants((node, pos) => {
      if (found) return false;
      if (node === grandParentMapped) { grandParentPos = pos + 1; found = true; return false; }
      return true;
    });
    if (!found) {
      // Try WEAK_NODE_TO_LORO_CONTAINER_MAPPING
      pmDoc.descendants((node, pos) => {
        if (found) return false;
        const cid = WEAK_NODE_TO_LORO_CONTAINER_MAPPING.get(node);
        if (cid === grandParent.id) { grandParentPos = pos + 1; found = true; return false; }
        return true;
      });
      if (!found) return null;
    }
  } else {
    return null;
  }

  // Sum sizes of preceding siblings to find blockMap's position
  let pos = grandParentPos;
  const listLen = parentList.length;
  for (let i = 0; i < listLen; i++) {
    const sibling = parentList.get(i);
    if (!sibling) continue;
    if ((sibling as any).id === blockMap.id) {
      return pos;
    }
    const siblingMapped = mapping.get((sibling as any).id);
    if (siblingMapped && !Array.isArray(siblingMapped)) {
      pos += (siblingMapped as import("prosemirror-model").Node).nodeSize;
    } else {
      let siblingSize = 0;
      pmDoc.descendants((node) => {
        const cid = WEAK_NODE_TO_LORO_CONTAINER_MAPPING.get(node);
        if (cid === (sibling as any).id) { siblingSize = node.nodeSize; return false; }
        return true;
      });
      if (siblingSize === 0) {
        return null;
      }
      pos += siblingSize;
    }
  }
  return null;
}


/**
 * Resolve the PM position of a `LoroText` whose mapping entry is missing
 * (typically because `updateLoroToPmState` pruned it after the LoroText
 * was fully emptied).
 *
 * The position is computed by walking the parent block's children list in
 * Loro and summing the PM `nodeSize` of the preceding mapped children.
 *
 * IMPORTANT: this function must NOT be called when the parent block's
 * children list has been mutated earlier in the same event batch — the
 * walk uses Loro's post-batch state but the returned position is in
 * pre-batch PM coordinates, and a sibling insert/delete in this batch
 * would silently shift the offset. Callers must guard with
 * `parentTouchedInBatch` (see {@link loroEventBatchToTransaction}).
 *
 * Returns `null` if the parent block is itself unmapped or the text
 * container is no longer in its parent.
 */
export function findEmptyTextPosition(
  pmDoc: Node,
  textId: ContainerID,
  mapping: LoroNodeMapping,
  loroDoc: LoroDocType,
): number | null {
  if (pmDoc == null || textId == null || mapping == null || loroDoc == null) {
    return null;
  }
  const text = loroDoc.getContainerById(textId);
  if (!(text instanceof LoroText)) {
    return null;
  }
  const parentList = text.parent();
  if (!(parentList instanceof LoroList)) {
    return null;
  }
  const parentBlock = parentList.parent();
  if (!(parentBlock instanceof LoroMap)) {
    return null;
  }

  const blockLoc = findContainerLocation(pmDoc, parentBlock.id, mapping, undefined, loroDoc);
  if (blockLoc == null || blockLoc.isText || Array.isArray(blockLoc.node)) {
    return null;
  }

  let textIdx = -1;
  for (let i = 0; i < parentList.length; i++) {
    const sibling = parentList.get(i);
    if (isContainer(sibling) && sibling.id === textId) {
      textIdx = i;
      break;
    }
  }
  if (textIdx === -1) {
    return null;
  }

  let offset = 0;
  for (let i = 0; i < textIdx; i++) {
    const sibling = parentList.get(i);
    if (!isContainer(sibling)) {
      return null;
    }
    const siblingMapped = mapping.get(sibling.id);
    if (siblingMapped == null) {
      // Another empty/unmapped LoroText contributes 0 to the offset.
      continue;
    }
    if (Array.isArray(siblingMapped)) {
      for (const n of siblingMapped) {
        offset += n.nodeSize;
      }
    } else {
      offset += siblingMapped.nodeSize;
    }
  }

  const isRoot = blockLoc.node === pmDoc;
  return (isRoot ? blockLoc.pos : blockLoc.pos + 1) + offset;
}

/**
 * Translate a `LoroEventBatch` into a ProseMirror `Transaction`.
 *
 * Returns `null` when any event in the batch cannot be translated — the
 * caller MUST fall back to a full document replace in that case so the
 * doc never diverges from Loro.
 *
 * Handled diff kinds:
 *   - `text`: insert / delete / mark add / mark remove inside a `LoroText`
 *   - `list`: block insert / delete / move on a parent's children list
 *   - `map`:  attribute updates on a block's `attributes` sub-map
 *
 * Other diff kinds (`tree`, `counter`) and any `event.by === "checkout"`
 * batch are routed to the fallback.
 */
export function loroEventBatchToTransaction(
  state: EditorState,
  batch: LoroEventBatch,
  mapping: LoroNodeMapping,
  doc: LoroDocType,
): Transaction | null {
  // Defensive null-checks. The plugin only ever calls this with a
  // well-formed batch from a real Loro subscription, but power users
  // are encouraged to compose this translator with their own dispatch
  // layer — return null gracefully on malformed input rather than
  // throwing a TypeError and crashing their fallback handler.
  if (batch == null || batch.events == null) {
    return null;
  }

  // Checkout events can carry diffs that essentially rewrite the document
  // (e.g. timeline scrubbing in a history viewer). Until we benchmark
  // them, route all checkouts through the safety-net rebuild. This check
  // is placed before the empty-batch shortcut so a synthetic batch with
  // by:"checkout" can't slip through.
  if (batch.by === "checkout") {
    return null;
  }
  if (batch.events.length === 0) {
    return state.tr;
  }

  const tr = state.tr;
  // Containers materialised into PM by a list-insert in this batch.
  // Subsequent events targeting any of them — or their descendants — are
  // skipped because the materialised PM subtree already reflects Loro's
  // post-batch state.
  const materialisedInBatch = new Set<ContainerID>();
  // Parent block ContainerIDs whose children list was mutated by some
  // earlier event in the batch (insert or delete). We use this to guard
  // findEmptyTextPosition, which only computes a correct offset when
  // neither the parent nor any ancestor's children list has been touched
  // in this batch (a sibling/ancestor mutation shifts pre-batch PM
  // coordinates that the parent-walk relies on).
  const parentTouchedInBatch = new Set<ContainerID>();
  // Block IDs whose subtree contains a dirty container — i.e. an
  // earlier event in this batch mutated some container within their
  // subtree (text-diff, list-diff, or map-diff). For these blocks,
  // pre-state child widths from `snapshotChildren` may differ from
  // their tr.doc widths (because a descendant text/list grew or
  // shrunk). When `applyListDiff` runs against such a block, the
  // `pmCursor` arithmetic against pre-state widths produces invalid
  // tr.doc positions — bail to fallback instead.
  //
  // Populated via `markContainerDirty` whenever an event mutates a
  // container; the helper walks UP and adds every ancestor block to
  // this set.
  const dirtyAncestorBlocks = new Set<ContainerID>();
  // Memoise findContainerLocation across the batch — without this it is
  // O(doc_size) per event and a 50-event batch on a 5KB doc is 250K
  // descendant visits.
  const locationCache = new Map<ContainerID, ContainerLocation | null>();

  const batchId = Math.random().toString(36).slice(2, 6);
  for (const event of batch.events) {
    if (materialisedInBatch.has(event.target)) {
      continue;
    }
    const ok = applyEvent(
      tr,
      state,
      event,
      mapping,
      doc,
      materialisedInBatch,
      parentTouchedInBatch,
      dirtyAncestorBlocks,
      locationCache,
    );
    if (!ok) {
      return null;
    }
    // Check if text container mapping is correct
    for (const [k, v] of mapping) {
      if (k.endsWith(":Text") && !Array.isArray(v)) {
      }
    }
  }
  return tr;
}

/**
 * Walk up from `target` and add every ancestor block (LoroMap with a
 * `nodeName`) ID to `set`. Used to mark "this block's subtree has had
 * a mutation" so subsequent list events on the block bail to fallback
 * (their pre-state child widths would be stale).
 */
function markAncestorsDirty(
  doc: LoroDocType,
  target: ContainerID,
  set: Set<ContainerID>,
): void {
  const c = doc.getContainerById(target);
  if (c == null) return;
  let p: unknown = c.parent();
  while (p != null) {
    if (p instanceof LoroMap && (p as LoroMap).get(NODE_NAME_KEY) != null) {
      set.add((p as LoroMap).id);
    }
    if (
      p instanceof LoroMap ||
      p instanceof LoroList ||
      p instanceof LoroText
    ) {
      p = (p as { parent: () => unknown }).parent();
    } else {
      break;
    }
  }
}

function applyEvent(
  tr: Transaction,
  state: EditorState,
  event: LoroEvent,
  mapping: LoroNodeMapping,
  doc: LoroDocType,
  materialisedInBatch: Set<ContainerID>,
  parentTouchedInBatch: Set<ContainerID>,
  dirtyAncestorBlocks: Set<ContainerID>,
  locationCache: Map<ContainerID, ContainerLocation | null>,
): boolean {
  switch (event.diff.type) {
    case "text":
      return applyTextDiff(
        tr,
        state,
        event.target,
        event.diff,
        mapping,
        doc,
        parentTouchedInBatch,
        dirtyAncestorBlocks,
        locationCache,
      );
    case "list":
      return applyListDiff(
        tr,
        state,
        event.target,
        event.diff,
        mapping,
        doc,
        materialisedInBatch,
        parentTouchedInBatch,
        dirtyAncestorBlocks,
        locationCache,
      );
    case "map":
      return applyMapDiff(
        tr,
        state,
        event.target,
        event.diff,
        mapping,
        doc,
        dirtyAncestorBlocks,
        locationCache,
      );
    default:
      // tree / counter — not used by this binding.
      return false;
  }
}

// ---------------------------------------------------------------------------
// Text
// ---------------------------------------------------------------------------

function applyTextDiff(
  tr: Transaction,
  state: EditorState,
  target: ContainerID,
  diff: TextDiff,
  mapping: LoroNodeMapping,
  doc: LoroDocType,
  parentTouchedInBatch: Set<ContainerID>,
  dirtyAncestorBlocks: Set<ContainerID>,
  locationCache: Map<ContainerID, ContainerLocation | null>,
): boolean {
  const loc = findContainerLocation(tr.doc, target, mapping, locationCache, doc);
  let prePos: number;
  let usedFallback = false;
  if (loc != null && loc.isText) {
    prePos = loc.pos;
  } else if (loc == null) {
    // Mapping miss: typical when the LoroText was emptied earlier in this
    // session and `updateLoroToPmState` pruned the entry. Walk to the
    // parent block to recover the insertion point — but only when no
    // ancestor's children list was mutated in THIS batch (see
    // findEmptyTextPosition's docs for why).
    const text = doc.getContainerById(target);
    if (!(text instanceof LoroText)) {
      return false;
    }
    if (anyAncestorTouched(text, parentTouchedInBatch)) {
      return false;
    }
    const fallback = findEmptyTextPosition(tr.doc, target, mapping, doc);
    if (fallback == null) {
    }
    if (fallback == null) {
      return false;
    }
    prePos = fallback;
    usedFallback = true;
  } else {
    // Container was found but isn't a text run — schema mismatch.
    return false;
  }

  let cursor = tr.mapping.map(prePos);
  for (const op of diff.diff as Delta<string>[]) {
    if (op.retain != null) {
      // A `retain: 0` is a legal no-op even on a freshly-emptied text;
      // only a positive retain is incompatible with the empty-text
      // fallback path (we'd be walking over characters that don't exist).
      if (usedFallback && op.retain > 0) {
        // The empty-text fallback was used but the diff has retain ops,
        // meaning the text container actually has content. This happens
        // when the mapping has a stale empty entry but the Loro text has
        // content. Use the Loro text's current length to validate.
        const loroText = doc.getContainerById(target);
        if (loroText instanceof LoroText && loroText.length >= op.retain) {
          // The Loro text has enough content — proceed with the retain.
          // The cursor position is correct (prePos is the start of the text run).
          cursor += op.retain;
          continue;
        }
        return false;
      }
      if (op.attributes && op.retain > 0) {
        if (
          !applyMarkAttributes(
            tr,
            state.schema,
            cursor,
            cursor + op.retain,
            op.attributes,
          )
        ) {
          return false;
        }
      }
      cursor += op.retain;
    } else if (op.insert != null) {
      const marks = op.attributes
        ? attributesToMarks(state.schema, op.attributes)
        : [];
      if (marks === null) {
        return false;
      }
      const textNode = state.schema.text(op.insert, marks);
      try {
        tr.insert(cursor, textNode);
      } catch (e) {
        return false;
      }
      cursor += op.insert.length;
    } else if (op.delete != null) {
      if (usedFallback) {
        return false;
      }
      tr.delete(cursor, cursor + op.delete);
    } else {
      return false;
    }
  }
  // Text mutation succeeded — mark the text container's ancestors
  // dirty so that a later list-event on any of them bails to
  // fallback (their pre-state child widths are now stale).
  markAncestorsDirty(doc, target, dirtyAncestorBlocks);
  return true;
}

/**
 * Returns true if any ancestor of the given Loro container has been
 * recorded in `parentTouchedInBatch` (the set of block IDs whose
 * children list was mutated earlier in this batch). The empty-text
 * fallback walks the parent block's pre-batch children to compute a
 * PM position; an insert/delete in any ancestor breaks that
 * invariant.
 */
function anyAncestorTouched(
  container: { parent: () => unknown } | null | undefined,
  parentTouchedInBatch: Set<ContainerID>,
): boolean {
  let node: unknown = container?.parent();
  while (node != null) {
    if (
      node instanceof LoroMap &&
      parentTouchedInBatch.has((node as LoroMap).id)
    ) {
      return true;
    }
    if (
      node instanceof LoroMap ||
      node instanceof LoroList ||
      node instanceof LoroText
    ) {
      node = (node as { parent: () => unknown }).parent();
    } else {
      break;
    }
  }
  return false;
}

/**
 * Convert a Loro text-attribute map to PM marks. Used when a delta op's
 * `insert` carries inline marks. Returns `null` if the schema does not
 * contain a referenced mark (caller bails to fallback).
 */
function attributesToMarks(
  schema: Schema,
  attributes: Record<string, Value | undefined>,
): Mark[] | null {
  const marks: Mark[] = [];
  for (const [name, raw] of Object.entries(attributes)) {
    if (raw == null) {
      continue;
    }
    const markType = schema.marks[name];
    if (markType == null) {
      return null;
    }
    const attrs = valueToAttrs(raw);
    marks.push(markType.create(attrs ?? undefined));
  }
  return marks;
}

/**
 * Apply a mark-attribute change over `[from, to)`.
 */
function applyMarkAttributes(
  tr: Transaction,
  schema: Schema,
  from: number,
  to: number,
  attributes: Record<string, Value | undefined>,
): boolean {
  for (const [name, raw] of Object.entries(attributes)) {
    const markType = schema.marks[name];
    if (markType == null) {
      return false;
    }
    if (raw == null) {
      tr.removeMark(from, to, markType);
    } else {
      const attrs = valueToAttrs(raw);
      tr.addMark(from, to, markType.create(attrs ?? undefined));
    }
  }
  return true;
}

// ---------------------------------------------------------------------------
// List (block-level edits on a parent's children list)
// ---------------------------------------------------------------------------

interface ListItemSnapshot {
  /**
   * The pre-state PM Node (or array of inline text nodes) for this child.
   * Captured so deletes can prune the mapping for the entire deleted
   * subtree.
   */
  pmNode: Node | Node[];
  /** PM offset of the start of this child relative to the parent's content. */
  pmStart: number;
  /** PM offset just past this child's content. */
  pmEnd: number;
}

function applyListDiff(
  tr: Transaction,
  state: EditorState,
  target: ContainerID,
  diff: { type: "list"; diff: Delta<(Value | Container)[]>[] },
  mapping: LoroNodeMapping,
  doc: LoroDocType,
  materialisedInBatch: Set<ContainerID>,
  parentTouchedInBatch: Set<ContainerID>,
  dirtyAncestorBlocks: Set<ContainerID>,
  locationCache: Map<ContainerID, ContainerLocation | null>,
): boolean {
  const loroList = doc.getContainerById(target);
  if (!(loroList instanceof LoroList)) {
    return false;
  }
  const parentMap = loroList.parent();
  if (!(parentMap instanceof LoroMap)) {
    return false;
  }
  if (parentMap.get(NODE_NAME_KEY) == null) {
    return false;
  }

  // If this parent already had a list event in the same batch,
  // bail to fallback. snapshotChildren operates on pre-state PM children
  // and the second pass would compute offsets against that pre-state
  // even though tr already contains the first event's inserts/deletes
  // — producing inconsistent absolute positions.
  if (parentTouchedInBatch.has(parentMap.id)) {
    return false;
  }
  // Also bail when ANY descendant of this block has been mutated by a
  // previous event in this batch. snapshotChildren reads pre-state PM
  // child widths, but any descendant mutation (text/list/map) changes
  // the descendant's tr.doc width — making `contentStart + pmCursor`
  // arithmetic land on the wrong tr.doc position. Concrete failure:
  // event 1 inserts a list-item into ul (size +6), event 5 deletes a
  // sibling paragraph from doc.children — without this guard, event 5's
  // tr.delete walks past ul's pre-state size and lands inside the
  // newly-inserted list-item, corrupting the doc.
  if (dirtyAncestorBlocks.has(parentMap.id)) {
    return false;
  }

  const parentLoc = findContainerLocation(
    tr.doc,
    parentMap.id,
    mapping,
    locationCache,
    doc,
  );
  if (parentLoc == null || parentLoc.isText) {
    return false;
  }
  const parentNode = parentLoc.node as Node;
  const parentPos = tr.mapping.map(parentLoc.pos);
  const isRootDoc = parentNode === state.doc;
  const contentStart = isRootDoc ? parentPos : parentPos + 1;

  const items = snapshotChildren(parentNode);

  let listIdx = 0;
  let pmCursor = 0;
  let listChanged = false;

  for (const op of diff.diff) {
    if (op.retain != null) {
      for (let i = 0; i < op.retain; i++) {
        if (listIdx >= items.length) {
          return false;
        }
        pmCursor += items[listIdx].pmEnd - items[listIdx].pmStart;
        listIdx++;
      }
    } else if (op.delete != null) {
      let removedSize = 0;
      const subtreesToPrune: (Node | Node[])[] = [];
      for (let i = 0; i < op.delete; i++) {
        if (listIdx >= items.length) {
          return false;
        }
        const item = items[listIdx];
        removedSize += item.pmEnd - item.pmStart;
        subtreesToPrune.push(item.pmNode);
        listIdx++;
      }
      if (removedSize > 0) {
        tr.delete(
          contentStart + pmCursor,
          contentStart + pmCursor + removedSize,
        );
        for (const subtree of subtreesToPrune) {
          pruneSubtreeFromMapping(subtree, mapping, locationCache);
        }
        listChanged = true;
      }
    } else if (op.insert != null) {
      const inserted = op.insert as (Value | Container)[];

      // Build the fragment in a *scratch* mapping copy so we don't pollute
      // `mapping` if validation fails. createNodeFromLoroObj uses `get` for
      // memoisation and `set` for new bindings, so the scratch needs to
      // contain every existing entry.
      const scratchMapping: LoroNodeMapping = new Map(mapping);
      const fragments: Node[] = [];
      const newlyMaterialised: Container[] = [];
      for (const value of inserted) {
        if (!isContainer(value)) {
          return false;
        }
        const node = materializeInsertedContainer(
          state.schema,
          value,
          scratchMapping,
        );
        if (node == null) {
          return false;
        }
        newlyMaterialised.push(value);
        if (Array.isArray(node)) {
          for (const n of node) fragments.push(n);
        } else {
          fragments.push(node);
        }
      }
      const fragment = Fragment.from(fragments);

      // Validate that the fragment can fit at the target position. If
      // PM would have to "open"/lift content for the insertion to be
      // valid, we'd diverge from Loro silently — better to bail to the
      // safety-net rebuild.
      const insertPos = contentStart + pmCursor;
      let $pos;
      try {
        $pos = tr.doc.resolve(insertPos);
      } catch {
        return false;
      }
      if (!$pos.parent.canReplace($pos.index(), $pos.index(), fragment)) {
        return false;
      }

      // Commit: insert the fragment and merge the scratch mapping back.
      tr.insert(insertPos, fragment);
      for (const [k, v] of scratchMapping) {
        mapping.set(k, v);
      }
      for (const container of newlyMaterialised) {
        collectContainerIds(container, materialisedInBatch);
      }
      pmCursor += fragment.size;
      listChanged = true;
    } else {
      return false;
    }
  }

  if (listChanged) {
    parentTouchedInBatch.add(parentMap.id);
    // The list mutation may have changed the parent block's overall
    // width in tr.doc (children added/removed). Mark every ancestor
    // block dirty so a later applyListDiff on any of them bails to
    // fallback rather than computing positions from stale pre-state
    // child widths.
    markAncestorsDirty(doc, target, dirtyAncestorBlocks);
  }
  return true;
}

/**
 * Walk a parent block's pre-state PM children and turn them into a flat
 * array aligned 1:1 with the Loro children list. Consecutive PM text
 * nodes that share a single `LoroText` are coalesced into one entry.
 */
function snapshotChildren(parent: Node): ListItemSnapshot[] {
  const items: ListItemSnapshot[] = [];
  let offset = 0;
  let i = 0;
  while (i < parent.childCount) {
    const child = parent.child(i);
    if (child.isText) {
      const runStart = offset;
      const run: Node[] = [];
      while (i < parent.childCount && parent.child(i).isText) {
        run.push(parent.child(i));
        offset += parent.child(i).nodeSize;
        i++;
      }
      items.push({ pmNode: run, pmStart: runStart, pmEnd: offset });
    } else {
      items.push({
        pmNode: child,
        pmStart: offset,
        pmEnd: offset + child.nodeSize,
      });
      offset += child.nodeSize;
      i++;
    }
  }
  return items;
}

/**
 * Recursively remove `mapping` entries for every Loro container bound to
 * a deleted PM subtree. Also invalidates `locationCache` entries for
 * the pruned IDs so a later event in the same batch cannot read a
 * stale location for a deleted container.
 *
 * For block PM Nodes we look up the ContainerID in the
 * `WEAK_NODE_TO_LORO_CONTAINER_MAPPING` reverse index and prune by id
 * (and recurse into block children). For text runs we scan `mapping`
 * for the entry whose value is the array of text nodes — O(n) per run
 * but only triggered on delete.
 */
function pruneSubtreeFromMapping(
  pmNode: Node | Node[],
  mapping: LoroNodeMapping,
  locationCache?: Map<ContainerID, ContainerLocation | null>,
): void {
  if (Array.isArray(pmNode)) {
    if (pmNode.length === 0) {
      return;
    }
    const cid = findContainerIdForTextRun(mapping, pmNode);
    if (cid != null) {
      mapping.delete(cid);
      locationCache?.delete(cid);
    }
    return;
  }
  // Look up the ContainerID for this block via the reverse WeakMap first,
  // then fall back to a scan of `mapping` itself. The fallback matters
  // for two cases: (a) a Node that travelled through `node.toJSON()` /
  // `nodeFromJSON` round-trip (it loses its WeakMap binding), and
  // (b) a freshly-inserted block whose Node was just dropped into the
  // tree by `tr.insert` rather than by `createNodeFromLoroObj`.
  const cid =
    WEAK_NODE_TO_LORO_CONTAINER_MAPPING.get(pmNode) ??
    findBlockContainerId(mapping, pmNode);
  if (cid != null) {
    mapping.delete(cid);
    locationCache?.delete(cid);
  }
  let i = 0;
  while (i < pmNode.childCount) {
    const child = pmNode.child(i);
    if (child.isText) {
      const run: Node[] = [];
      while (i < pmNode.childCount && pmNode.child(i).isText) {
        run.push(pmNode.child(i));
        i++;
      }
      pruneSubtreeFromMapping(run, mapping, locationCache);
    } else {
      pruneSubtreeFromMapping(child, mapping, locationCache);
      i++;
    }
  }
}

function findContainerIdForTextRun(
  mapping: LoroNodeMapping,
  run: Node[],
): ContainerID | null {
  const first = run[0];
  for (const [id, value] of mapping) {
    if (Array.isArray(value) && value.includes(first)) {
      return id;
    }
  }
  return null;
}

function findBlockContainerId(
  mapping: LoroNodeMapping,
  block: Node,
): ContainerID | null {
  for (const [id, value] of mapping) {
    if (value === block) {
      return id;
    }
  }
  return null;
}

/**
 * Recursively collect every container ID inside a freshly-inserted
 * subtree, so that later events targeting any of them in the same batch
 * are skipped.
 */
function collectContainerIds(
  container: Container,
  set: Set<ContainerID>,
): void {
  set.add(container.id);
  if (container instanceof LoroMap) {
    for (const key of container.keys()) {
      const value = container.get(key);
      if (isContainer(value)) {
        collectContainerIds(value, set);
      }
    }
  } else if (container instanceof LoroList) {
    for (let i = 0; i < container.length; i++) {
      const value = container.get(i);
      if (isContainer(value)) {
        collectContainerIds(value, set);
      }
    }
  }
}

/**
 * Materialise a container that was just inserted into Loro into a PM
 * Node (or array of inline text nodes for `LoroText`), populating the
 * mapping with fresh bindings for it and any nested containers.
 *
 * Returns `null` for container types this binding does not support
 * (e.g. `LoroTree`); the caller bails to fallback.
 */
function materializeInsertedContainer(
  schema: Schema,
  container: Container,
  mapping: LoroNodeMapping,
): Node | Node[] | null {
  if (container instanceof LoroMap) {
    return createNodeFromLoroObj(
      schema,
      container as LoroMap<LoroNodeContainerType>,
      mapping,
    );
  }
  if (container instanceof LoroText) {
    return createNodeFromLoroObj(schema, container, mapping);
  }
  return null;
}

// ---------------------------------------------------------------------------
// Map (attribute updates on a block's `attributes` sub-map)
// ---------------------------------------------------------------------------

function applyMapDiff(
  tr: Transaction,
  state: EditorState,
  target: ContainerID,
  diff: MapDiff,
  mapping: LoroNodeMapping,
  doc: LoroDocType,
  dirtyAncestorBlocks: Set<ContainerID>,
  locationCache: Map<ContainerID, ContainerLocation | null>,
): boolean {
  const container = doc.getContainerById(target);
  if (!(container instanceof LoroMap)) {
    return false;
  }
  const parent = container.parent();
  if (!(parent instanceof LoroMap)) {
    return false;
  }
  // Only handle map diffs on a block's `attributes` sub-map. A diff on
  // the block itself (e.g. nodeName change) or on an unrelated top-level
  // map falls back to the safety net.
  if (parent.get(NODE_NAME_KEY) == null) {
    return false;
  }
  const attrsContainer = parent.get(ATTRIBUTES_KEY);
  if (!(attrsContainer instanceof LoroMap) || attrsContainer.id !== target) {
    return false;
  }

  // If a prior event already mutated this block's attributes, bail.
  // Our `newAttrs = { ...blockNode.attrs, ...diff.updated }` reads
  // pre-state attrs from the cached PM node, so a second diff would
  // miss the first diff's changes. Loro typically coalesces multiple
  // attr changes per container into one MapDiff, so this case is
  // rare — but it CAN occur in checkout/replay scenarios.
  //
  // Track via dirtyAncestorBlocks: when a previous applyMapDiff ran
  // on this block, it added the block's id. Re-targeting the same
  // block is detected here.
  if (dirtyAncestorBlocks.has(parent.id)) {
    return false;
  }

  const blockLoc = findContainerLocation(
    state.doc,
    parent.id,
    mapping,
    locationCache,
    doc,
  );
  if (blockLoc == null || blockLoc.isText || Array.isArray(blockLoc.node)) {
    return false;
  }
  const blockNode = blockLoc.node;
  const blockPos = tr.mapping.map(blockLoc.pos);

  const newAttrs: { [key: string]: unknown } = { ...blockNode.attrs };
  for (const [key, raw] of Object.entries(diff.updated)) {
    if (raw === undefined || raw === null) {
      delete newAttrs[key];
    } else if (isContainer(raw)) {
      return false;
    } else {
      newAttrs[key] = raw;
    }
  }

  try {
    tr.setNodeMarkup(blockPos, undefined, newAttrs);
    // Update the mapping to point to the new node (setNodeMarkup creates a new node object)
    try {
      const newNode = tr.doc.nodeAt(blockPos);
      if (newNode) {
        mapping.set(parent.id, newNode);
        WEAK_NODE_TO_LORO_CONTAINER_MAPPING.set(newNode, parent.id);
        locationCache.delete(parent.id); // invalidate so next lookup uses new node
      }
    } catch (_) { /* ignore */ }
  } catch {
    return false;
  }
  // Mark this block (and ancestors) as dirty so a later list event
  // on an ancestor bails — attribute changes can affect a node's
  // PM nodeSize for nodes whose toDOM depends on attrs (rare but
  // possible). Conservative.
  markAncestorsDirty(doc, target, dirtyAncestorBlocks);
  return true;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function valueToAttrs(value: Value): { [key: string]: unknown } | null {
  if (
    value != null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    !(value instanceof Uint8Array)
  ) {
    return value as { [key: string]: unknown };
  }
  return null;
}
